import axios from 'axios';

// Define the base URL for your backend API
// Use the Render URL in production, and a local URL for development
const API_URL = process.env.NODE_ENV === 'production'
  ? 'https://your-render-backend-url.onrender.com' // <-- IMPORTANT: Replace with your actual Render URL
  : 'http://localhost:3001';

const api = axios.create({
  baseURL: API_URL,
  // DO NOT set a default Content-Type header here.
  // Axios will automatically set the correct 'multipart/form-data' header
  // when it detects a FormData object.
});

// Interceptor to add the auth token to every request
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

export default api;
